import{_ as a,o as r,c as t,au as l}from"./chunks/framework.Bpqx6pAq.js";const u=JSON.parse('{"title":"Layer utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/utilities/utils.layers.md","filePath":"api/map/utilities/utils.layers.md"}'),o={name:"api/map/utilities/utils.layers.md"};function i(s,e,d,c,n,y){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="layer-utilities" tabindex="-1">Layer utilities <a class="header-anchor" href="#layer-utilities" aria-label="Permalink to &quot;Layer utilities&quot;">‚Äã</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">‚Äã</a></h2><p>This module provides a comprehensive set of helper functions for layer classification, caching, editing, saving, and managing layer styles and filters. It also exposes functions for generating layer legends and definitions from imported GeoJSON data.</p><h2 id="classification-functions" tabindex="-1">Classification Functions <a class="header-anchor" href="#classification-functions" aria-label="Permalink to &quot;Classification Functions&quot;">‚Äã</a></h2><h3 id="isinmemorylayer-layer" tabindex="-1"><code>isInMemoryLayer(layer)</code> <a class="header-anchor" href="#isinmemorylayer-layer" aria-label="Permalink to &quot;`isInMemoryLayer(layer)`&quot;">‚Äã</a></h3><p>Returns <code>true</code> if the layer has no <code>_id</code> property (i.e. it exists only in memory and has not been persisted to the catalog).</p><hr><h3 id="isuserlayer-layer" tabindex="-1"><code>isUserLayer(layer)</code> <a class="header-anchor" href="#isuserlayer-layer" aria-label="Permalink to &quot;`isUserLayer(layer)`&quot;">‚Äã</a></h3><p>Returns <code>true</code> if <code>layer.scope === &#39;user&#39;</code>.</p><hr><h3 id="isfeaturelayer-layer" tabindex="-1"><code>isFeatureLayer(layer)</code> <a class="header-anchor" href="#isfeaturelayer-layer" aria-label="Permalink to &quot;`isFeatureLayer(layer)`&quot;">‚Äã</a></h3><p>Returns <code>true</code> if <code>layer.service === &#39;features&#39;</code>.</p><hr><h3 id="hasfeatureschema-layer" tabindex="-1"><code>hasFeatureSchema(layer)</code> <a class="header-anchor" href="#hasfeatureschema-layer" aria-label="Permalink to &quot;`hasFeatureSchema(layer)`&quot;">‚Äã</a></h3><p>Returns <code>true</code> if the layer has a <code>schema</code> property.</p><hr><h3 id="islayerselectable-layer" tabindex="-1"><code>isLayerSelectable(layer)</code> <a class="header-anchor" href="#islayerselectable-layer" aria-label="Permalink to &quot;`isLayerSelectable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>layer.isSelectable</code> (defaults to <code>true</code>).</p><hr><h3 id="islayerhighlightable-layer" tabindex="-1"><code>isLayerHighlightable(layer)</code> <a class="header-anchor" href="#islayerhighlightable-layer" aria-label="Permalink to &quot;`isLayerHighlightable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>layer.isHighlightable</code> (defaults to <code>true</code>).</p><hr><h3 id="islayerprobable-layer" tabindex="-1"><code>isLayerProbable(layer)</code> <a class="header-anchor" href="#islayerprobable-layer" aria-label="Permalink to &quot;`isLayerProbable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>layer.isProbable</code> (defaults to <code>false</code>).</p><hr><h3 id="islayerstorable-layer" tabindex="-1"><code>isLayerStorable(layer)</code> <a class="header-anchor" href="#islayerstorable-layer" aria-label="Permalink to &quot;`isLayerStorable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>true</code> if the layer can be saved to the catalog. Only in-memory layers (no <code>_id</code>) are storable. Defaults to <code>isUserLayer(layer)</code> unless overridden by <code>layer.isStorable</code>.</p><hr><h3 id="islayereditable-layer" tabindex="-1"><code>isLayerEditable(layer)</code> <a class="header-anchor" href="#islayereditable-layer" aria-label="Permalink to &quot;`isLayerEditable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>layer.isEditable</code> (defaults to <code>isUserLayer(layer)</code>).</p><hr><h3 id="islayercachable-layer" tabindex="-1"><code>isLayerCachable(layer)</code> <a class="header-anchor" href="#islayercachable-layer" aria-label="Permalink to &quot;`isLayerCachable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>true</code> if the layer can be cached for offline use. Defaults to <code>true</code> for base layers, service-backed layers, pmtiles layers, and geoJson layers.</p><hr><h3 id="islayerremovable-layer" tabindex="-1"><code>isLayerRemovable(layer)</code> <a class="header-anchor" href="#islayerremovable-layer" aria-label="Permalink to &quot;`isLayerRemovable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>layer.isRemovable</code> (defaults to <code>isUserLayer(layer)</code>).</p><hr><h3 id="islayerstyleeditable-layer" tabindex="-1"><code>isLayerStyleEditable(layer)</code> <a class="header-anchor" href="#islayerstyleeditable-layer" aria-label="Permalink to &quot;`isLayerStyleEditable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>layer.isStyleEditable</code> (defaults to <code>isUserLayer(layer)</code>).</p><hr><h3 id="islayerdataeditable-layer" tabindex="-1"><code>isLayerDataEditable(layer)</code> <a class="header-anchor" href="#islayerdataeditable-layer" aria-label="Permalink to &quot;`isLayerDataEditable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>layer.isDataEditable</code> (defaults to <code>isUserLayer(layer) &amp;&amp; isFeatureLayer(layer)</code>).</p><hr><h3 id="islayerfiltereditable-layer" tabindex="-1"><code>isLayerFilterEditable(layer)</code> <a class="header-anchor" href="#islayerfiltereditable-layer" aria-label="Permalink to &quot;`isLayerFilterEditable(layer)`&quot;">‚Äã</a></h3><p>Returns <code>layer.isFilterEditable</code> (defaults to <code>isUserLayer(layer) &amp;&amp; isFeatureLayer(layer)</code>).</p><hr><h3 id="isterrainlayer-layer" tabindex="-1"><code>isTerrainLayer(layer)</code> <a class="header-anchor" href="#isterrainlayer-layer" aria-label="Permalink to &quot;`isTerrainLayer(layer)`&quot;">‚Äã</a></h3><p>Returns <code>true</code> if the layer is a terrain layer (<code>type === &#39;TerrainLayer&#39;</code> or Cesium type <code>Cesium</code>/<code>Ellipsoid</code>).</p><hr><h3 id="ismeasurelayer-layer" tabindex="-1"><code>isMeasureLayer(layer)</code> <a class="header-anchor" href="#ismeasurelayer-layer" aria-label="Permalink to &quot;`isMeasureLayer(layer)`&quot;">‚Äã</a></h3><p>Returns <code>true</code> if the layer has both <code>variables</code> and <code>service</code> properties.</p><h2 id="cache-functions" tabindex="-1">Cache Functions <a class="header-anchor" href="#cache-functions" aria-label="Permalink to &quot;Cache Functions&quot;">‚Äã</a></h2><h3 id="islayercached-layer" tabindex="-1"><code>isLayerCached(layer)</code> <a class="header-anchor" href="#islayercached-layer" aria-label="Permalink to &quot;`isLayerCached(layer)`&quot;">‚Äã</a></h3><p>Checks whether the layer source URL is present in <code>LocalCache</code>.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;boolean&gt;</code></li></ul><hr><h3 id="setlayercached-layer-options" tabindex="-1"><code>setLayerCached(layer, options)</code> <a class="header-anchor" href="#setlayercached-layer-options" aria-label="Permalink to &quot;`setLayerCached(layer, options)`&quot;">‚Äã</a></h3><p>Caches the layer data for offline use. Dispatches to the appropriate cache strategy based on layer type:</p><ul><li><p><strong>Base layers</strong>: Tiles for each zoom level in the given bounds.</p></li><li><p><strong>Service layers</strong>: Creates an offline features service.</p></li><li><p><strong>GeoJSON layers</strong>: Caches the source URL response.</p></li><li><p><strong>PMTiles layers</strong>: Caches tile data including header and directory ranges.</p></li><li><p><strong>Parameters:</strong></p><ul><li><code>layer</code> <em>(Object)</em>: The layer to cache.</li><li><code>options.bounds</code> <em>(Array)</em>: <code>[[south, west], [north, east]]</code> bounding box.</li><li><code>options.minZoom</code> <em>(number, optional)</em>: Minimum zoom level. Defaults to <code>3</code>.</li><li><code>options.maxZoom</code> <em>(number, optional)</em>: Maximum zoom level.</li><li><code>options.nbConcurrentRequests</code> <em>(number, optional)</em>: Maximum concurrent cache requests. Defaults to <code>10</code>.</li></ul></li><li><p><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></p></li></ul><hr><h3 id="setlayeruncached-layer-options" tabindex="-1"><code>setLayerUncached(layer, options)</code> <a class="header-anchor" href="#setlayeruncached-layer-options" aria-label="Permalink to &quot;`setLayerUncached(layer, options)`&quot;">‚Äã</a></h3><p>Removes cached data for the layer. Mirrors <code>setLayerCached</code> for the corresponding layer type.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><hr><h3 id="setbaselayercached-layer-options-setgeojsonlayercached-layer-setpmtileslayercached-layer-options" tabindex="-1"><code>setBaseLayerCached(layer, options)</code> / <code>setGeojsonLayerCached(layer)</code> / <code>setPMTilesLayerCached(layer, options)</code> <a class="header-anchor" href="#setbaselayercached-layer-options-setgeojsonlayercached-layer-setpmtileslayercached-layer-options" aria-label="Permalink to &quot;`setBaseLayerCached(layer, options)` / `setGeojsonLayerCached(layer)` / `setPMTilesLayerCached(layer, options)`&quot;">‚Äã</a></h3><p>Type-specific cache functions. Prefer the generic <code>setLayerCached</code>.</p><h2 id="edit-functions" tabindex="-1">Edit Functions <a class="header-anchor" href="#edit-functions" aria-label="Permalink to &quot;Edit Functions&quot;">‚Äã</a></h2><h3 id="editlayerstyle-layer-style-ignorefeaturestyle" tabindex="-1"><code>editLayerStyle(layer, style, ignoreFeatureStyle?)</code> <a class="header-anchor" href="#editlayerstyle-layer-style-ignorefeaturestyle" aria-label="Permalink to &quot;`editLayerStyle(layer, style, ignoreFeatureStyle?)`&quot;">‚Äã</a></h3><p>Updates the style of a layer. For persisted layers (<code>layer._id</code>), patches the catalog service. For in-memory layers, updates the layer object directly. Regenerates legend and filter style templates as needed.</p><ul><li><strong>Parameters:</strong><ul><li><code>layer</code> <em>(Object)</em>: The layer to update.</li><li><code>style</code> <em>(Object)</em>: A <code>{ point, line, polygon }</code> style object.</li><li><code>ignoreFeatureStyle</code> <em>(boolean, optional)</em>: When <code>true</code>, sets <code>ignoreFeatureStyle</code> on the patch.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> ‚Äî The updated layer.</li></ul><hr><h3 id="updatelayerwithfiltersstyle-layer" tabindex="-1"><code>updateLayerWithFiltersStyle(layer)</code> <a class="header-anchor" href="#updatelayerwithfiltersstyle-layer" aria-label="Permalink to &quot;`updateLayerWithFiltersStyle(layer)`&quot;">‚Äã</a></h3><p>Regenerates the style templates for a persisted layer from its filter definitions and patches the catalog service.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><hr><h3 id="editfilterstyle-layer-filter-enginestyle-style-ignorefeaturestyle" tabindex="-1"><code>editFilterStyle(layer, filter, engineStyle, style, ignoreFeatureStyle?)</code> <a class="header-anchor" href="#editfilterstyle-layer-filter-enginestyle-style-ignorefeaturestyle" aria-label="Permalink to &quot;`editFilterStyle(layer, filter, engineStyle, style, ignoreFeatureStyle?)`&quot;">‚Äã</a></h3><p>Updates the style of a specific filter on a layer and regenerates all style templates. Patches the catalog service with the new templates and filter list.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><hr><h3 id="getlegendforlayer-layer" tabindex="-1"><code>getLegendForLayer(layer)</code> <a class="header-anchor" href="#getlegendforlayer-layer" aria-label="Permalink to &quot;`getLegendForLayer(layer)`&quot;">‚Äã</a></h3><p>Generates the legend descriptor for a layer without mutating it:</p><ul><li><p>If the layer has filters with styles, generates a symbol-based legend from filter styles.</p></li><li><p>Otherwise generates a single legend from the default layer style.</p></li><li><p><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> ‚Äî A legend patch object <code>{ legend, filters? }</code> or <code>{ $unset: { legend: &#39;&#39; } }</code> when no filter has a style.</p></li></ul><hr><h3 id="getfilterfunctionfromlayerfilters-layer" tabindex="-1"><code>getFilterFunctionFromLayerFilters(layer)</code> <a class="header-anchor" href="#getfilterfunctionfromlayerfilters-layer" aria-label="Permalink to &quot;`getFilterFunctionFromLayerFilters(layer)`&quot;">‚Äã</a></h3><p>Builds a <code>sift</code>-based filter function from the layer&#39;s filter definitions. Active filters are combined with <code>filterOperators.active</code> (default <code>$or</code>) and inactive filters with <code>filterOperators.inactive</code> (default <code>$and</code>).</p><ul><li><strong>Returns:</strong> <code>Function</code> ‚Äî A predicate function <code>(item) =&gt; boolean</code>.</li></ul><h2 id="layer-crud-functions" tabindex="-1">Layer CRUD Functions <a class="header-anchor" href="#layer-crud-functions" aria-label="Permalink to &quot;Layer CRUD Functions&quot;">‚Äã</a></h2><h3 id="generatelayerdefinition-layerspec-geojson" tabindex="-1"><code>generateLayerDefinition(layerSpec, geoJson)</code> <a class="header-anchor" href="#generatelayerdefinition-layerspec-geojson" aria-label="Permalink to &quot;`generateLayerDefinition(layerSpec, geoJson)`&quot;">‚Äã</a></h3><p>Populates a layer specification object from a GeoJSON dataset. Sets default engine options (<code>geoJson</code>, <code>realtime</code>), generates a property schema if absent, assigns feature IDs, and extracts custom pane definitions from feature styles.</p><ul><li><strong>Parameters:</strong><ul><li><code>layerSpec</code> <em>(Object)</em>: The layer specification to populate in place.</li><li><code>geoJson</code> <em>(Object)</em>: A GeoJSON Feature or FeatureCollection.</li></ul></li><li><strong>Returns:</strong> <code>true</code> if the GeoJSON is valid, or <code>undefined</code> on error.</li></ul><hr><h3 id="savegeojsonlayer-layer-geojson-chunksize" tabindex="-1"><code>saveGeoJsonLayer(layer, geoJson, chunkSize?)</code> <a class="header-anchor" href="#savegeojsonlayer-layer-geojson-chunksize" aria-label="Permalink to &quot;`saveGeoJsonLayer(layer, geoJson, chunkSize?)`&quot;">‚Äã</a></h3><p>Saves an in-memory GeoJSON layer to the catalog and features service. Validates geometry, uploads features in chunks (default 5000 points per chunk), and enables tiling for large datasets (&gt;5000 points).</p><ul><li><strong>Returns:</strong> <code>Promise&lt;Object | undefined&gt;</code> ‚Äî The created catalog layer, or <code>undefined</code> if the user cancelled after geometry errors.</li></ul><hr><h3 id="savelayer-layer" tabindex="-1"><code>saveLayer(layer)</code> <a class="header-anchor" href="#savelayer-layer" aria-label="Permalink to &quot;`saveLayer(layer)`&quot;">‚Äã</a></h3><p>Saves a layer definition to the catalog service without uploading features.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> ‚Äî The created catalog layer.</li></ul><hr><h3 id="removelayer-layer" tabindex="-1"><code>removeLayer(layer)</code> <a class="header-anchor" href="#removelayer-layer" aria-label="Permalink to &quot;`removeLayer(layer)`&quot;">‚Äã</a></h3><p>Prompts the user for confirmation, then removes the layer from the catalog and (for feature layers) removes all associated features.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;boolean&gt;</code> ‚Äî <code>true</code> if removed, <code>false</code> if the user cancelled.</li></ul>',102)])])}const p=a(o,[["render",i]]);export{u as __pageData,p as default};
